<!-- SweetAlert Kütüphanesi Eklemesi -->
<script src="https://cdn.jsdelivr.net/npm/sweetalert2@10"></script>
<script>
    document.getElementById("kopyalaButonu").addEventListener("click", function() {
        var metinSatiri = document.getElementById("metinSatiri");
        
        // Metni seç ve kopyala
        var sec = window.getSelection();
        var range = document.createRange();
        range.selectNodeContents(metinSatiri);
        sec.removeAllRanges();
        sec.addRange(range);
        document.execCommand("copy");
        
        // SweetAlert kullanarak kullanıcı geribildirimini göster
        Swal.fire({
            icon: 'success',
            html: '<strong>IBAN Kopyalandı</strong><br>' + metinSatiri.innerText,
            confirmButtonText: 'Tamam'
        });
    });
</script>

<script>
    document.getElementById('checkboxform').addEventListener('submit', function (event) {
        // Checkbox seçili değilse, değeri ekleyip true olarak ayarla
        if (!document.getElementById('tdUMoXdmvU').checked) {
            var input = document.createElement('input');
            input.type = 'hidden';
            input.name = 'Sözleşme';
            input.value = 'true';
            this.appendChild(input);
        }
    });
</script>

